FIELD_MARGIN_Y = 40
FIELD_WIDTH = SCREEN_WIDTH - 2 * FIELD_MARGIN_X
FIELD_HEIGHT = SCREEN_HEIGHT - 2 * FIELD_MARGIN_Y
FIELD_LEFT = FIELD_MARGIN_X
FIELD_TOP = FIELD_MARGIN_Y
FIELD_RIGHT = FIELD_LEFT + FIELD_WIDTH
